// can be changed not only form outside but also from inside the mx-menu-item-v2 component

export interface IMenuItemV2State {
  displayChildren?: boolean;
  selected?: boolean;
  indeterminate?: boolean;
}

// can be changed only from outside the mx-menu-item-v2 component
export interface IMenuItemV2Props {
  showCheckbox?: boolean;
  showTitle?: boolean;
  compactCheckbox?: boolean;
  hideCaret?: boolean;
  showChildCount?: boolean;
  important?: boolean;
  storeDisplayChildren?: boolean;
  disabled?: boolean;
}

export interface IMenuItemV2 extends IMenuItemV2State, IMenuItemV2Props {
  label: string;
  value: string;
  children?: IMenuItemV2[];
  data?: any;
}

export class CustomKeysV2 {
  key: string;
  value: string;
}

export interface IMenuItemV2Entry extends Omit<IMenuItemV2, 'children'> {
  id: string;
  parentId: string | null;
  children: string[];
  storedDisplayChildren: boolean;
  originalItem: IMenuItemV2;
}

export interface ISelectedIndeterminate {
  selected: boolean;
  indeterminate: boolean;
}

export interface IDisabledSelected {
  disabled: boolean;
  selected: boolean;
}

export type MenuItemV2Map = { [key: string]: IMenuItemV2Entry };
export type MenuItemV2StateMap = { [key: string]: IMenuItemV2State };

export interface IMenuItemV2CurrentState {
  item: IMenuItemV2;
  currentSelectedState: IMenuItemV2State;
  originalItem: IMenuItemV2;
  fullStateItem: IMenuItemV2;
  fixedStateMap: MenuItemV2Map;
}

export const defaultMenuItemState: IMenuItemV2State = {
  displayChildren: true,
  selected: false,
  indeterminate: false
};

export const defaultMenuItemProps: IMenuItemV2Props = {
  showCheckbox: false,
  showTitle: false,
  compactCheckbox: false,
  hideCaret: false,
  showChildCount: false,
  important: false,
  storeDisplayChildren: false,
  disabled: false
};
