import {
  CustomKeysV2,
  defaultMenuItemProps,
  defaultMenuItemState,
  IDisabledSelected,
  IMenuItemV2,
  IMenuItemV2Entry,
  IMenuItemV2Props,
  ISelectedIndeterminate,
  MenuItemV2Map, MenuItemV2StateMap
} from '@src/mx-components/menu-item/mx-menu-item-v2/mx-menu-item-v2.model';
import { MxWebComponentsService } from '@src/utils/mx-utils/mx-web-components.service';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { SelectListItem } from '@src/utils/mx-utils/calendar-service';
import { TreeMenuItem } from '@src/mx-components/menu-item/mx-menu-item/menu-item.interface';

const minListHeight: number = 324;

const mxService: MxWebComponentsService = MxWebComponentsService.Instance;

const unchangeableProps: string[] = Object.keys(defaultMenuItemProps).filter((v: string) => v !== 'important');

const convertStringToItem = (item: IMenuItemV2 | string, compact: boolean, showCheckbox: boolean): IMenuItemV2 => {
  if (typeof item === 'string') {
    return {
      label: item,
      value: item,
      ...defaultMenuItemState,
      ...defaultMenuItemProps,
      compactCheckbox: compact,
      showCheckbox: showCheckbox,
      children: []
    } as IMenuItemV2;
  }
  return { ...item };
};

const convertStringItemsArrayToObjectsArray = (
  items: IMenuItemV2[] | string[],
  compact: boolean,
  showCheckbox: boolean): IMenuItemV2[] => {
  return items
    .map((item: IMenuItemV2 | string) => convertStringToItem(item, compact, showCheckbox)) as IMenuItemV2[];
};

const composeItemMap = (
  item: IMenuItemV2,
  customKeys: CustomKeysV2,
  selectedItemsMap: MenuItemV2StateMap,
  updatedItemsMap: MenuItemV2StateMap,
  rootId: string,
  propsToOverride: IMenuItemV2Props = {}): MenuItemV2Map => {
  const resultMap: MenuItemV2Map = {};
  composeItemMapAccumulated(item, customKeys, resultMap, selectedItemsMap, updatedItemsMap, rootId, propsToOverride);
  return resultMap;
};

const composeItemMapAccumulated = (
  item: IMenuItemV2,
  customKeys: CustomKeysV2,
  resultMap: MenuItemV2Map,
  selectedItemsMap: MenuItemV2StateMap,
  updatedItemsMap: MenuItemV2StateMap,
  rootId: string,
  propsToOverride: IMenuItemV2Props = {}): void => {
  if (isNullOrUndefined(item)) {
    mxService.logWarning('No item model was provided.');
    return;
  }
  let label: string = item.label;
  let value: string = item.value;
  if (hasCustomKeys(customKeys)) {
    label = item[customKeys.key];
    value = item[customKeys.value];
  }
  const composedParent: IMenuItemV2 = { ...defaultMenuItemProps, ...item };
  const composedRootItem: IMenuItemV2Entry = generateItemEntry(
    { id: rootId, label, value },
    item,
    null,
    composedParent,
    selectedItemsMap,
    updatedItemsMap,
    propsToOverride
  );
  composedRootItem.children = composeChildren(
    rootId,
    composedParent,
    selectedItemsMap,
    updatedItemsMap,
    customKeys,
    propsToOverride,
    resultMap);
  updateDisabled(composedRootItem, resultMap);
  resultMap[rootId] = composedRootItem;
};

const hasCustomKeys = (customKeys: CustomKeysV2 | null): boolean => {
  return customKeys &&
    !isNullOrUndefinedOrEmptyString(customKeys.value) &&
    !isNullOrUndefinedOrEmptyString(customKeys.key);
};

const composeItemWithCurrentStateFromMap = (itemsMap: MenuItemV2Map, id: string): IMenuItemV2 => {
  const entry: IMenuItemV2Entry = itemsMap[id];
  if (entry == null) {
    return null;
  }
  const fullItem: IMenuItemV2 = {
    ...entry.originalItem,
    ...entry, // spread the entry to get the state and props
    children: [] // initialize children as empty array
  };
  // propagate the original children from the entry
  if (entry.children && entry.children.length > 0) {
    fullItem.children = entry.children.map((childId: string) => {
      return composeItemWithCurrentStateFromMap(itemsMap, childId); // recursively compose full item for each child
    }).filter((child): child is IMenuItemV2 => child !== null);
  }
  return fullItem;
};

const composeChildren = (
  parentId: string,
  parent: IMenuItemV2,
  selectedItemsMap: MenuItemV2StateMap,
  updatedItemsMap: MenuItemV2StateMap,
  customKeys: CustomKeysV2,
  propsToOverride: IMenuItemV2Props,
  resultMap: MenuItemV2Map): string[] => {
  if (!parent.hasOwnProperty('children') || parent.children.length === 0) {
    return [];
  }
  return parent.children.map((child: IMenuItemV2) => {
    const id: string = hasCustomKeys(customKeys) ? child[customKeys.value] : child.value;
    const label: string = hasCustomKeys(customKeys) ? child[customKeys.key] : child.label;
    const composedChild: IMenuItemV2Entry = generateItemEntry(
      { id, label, value: id },
      child,
      parentId,
      parent,
      selectedItemsMap,
      updatedItemsMap,
      propsToOverride);
    const itemWithUpdatedProps: IMenuItemV2 = propagatePropToChild(unchangeableProps, parent, child);
    composedChild.children = composeChildren(
      id,
      itemWithUpdatedProps,
      selectedItemsMap,
      updatedItemsMap,
      customKeys,
      propsToOverride,
      resultMap);
    updateDisabled(composedChild, resultMap);
    resultMap[id] = composedChild;
    return id;
  });
};

const updateDisabled = (item: IMenuItemV2Entry, resultMap: MenuItemV2Map): void => {
  if (item.children.length === 0) {
    return;
  }
  let disabledCount = 0;
  item.children.forEach((childrenId: string) => {
    // assuming child already in the result map
    if (resultMap[childrenId].disabled) {
      disabledCount++;
    }
  });
  const disabled = disabledCount === item.children.length;
  if (disabled && !item.disabled) {
    item.disabled = true;
  }
};

const generateItemEntry = (
  mainFields: { id: string; label: string; value: string; },
  originalItem: IMenuItemV2,
  parentId: string,
  parent: IMenuItemV2,
  selectedItemsMap: MenuItemV2StateMap,
  updatedItemsMap: MenuItemV2StateMap,
  propsToOverride: IMenuItemV2Props = {}): IMenuItemV2Entry => {
  const { id, label, value } = mainFields;
  const defaultDisplayChildren: boolean = defaultMenuItemState.displayChildren;
  const itemWithUpdatedProps: IMenuItemV2 = propagatePropToChild(
    unchangeableProps,
    { ...parent, ...propsToOverride },
    originalItem);
  if (selectedItemsMap.hasOwnProperty(id)) {
    itemWithUpdatedProps.selected = selectedItemsMap[id].selected;
  }
  if (updatedItemsMap.hasOwnProperty(id)) {
    itemWithUpdatedProps.selected = updatedItemsMap[id].selected;
    itemWithUpdatedProps.displayChildren = updatedItemsMap[id].displayChildren;
  }
  return {
    ...defaultMenuItemState,
    ...itemWithUpdatedProps,
    label,
    value,
    originalItem: { ...originalItem },
    children: [],
    storedDisplayChildren: originalItem.hasOwnProperty('displayChildren') ?
      originalItem.displayChildren :
      defaultDisplayChildren,
    id,
    parentId,
    ...propsToOverride
  };
};

const composeSelectedTree = (itemsMap: MenuItemV2Map): IMenuItemV2[] | string[] => {
  const root: IMenuItemV2Entry = itemsMap['root'];
  if (root.selected) {
    return [root.originalItem];
  }
  const originalItemsList: IMenuItemV2[] = [];
  if (!root.indeterminate) {
    return originalItemsList;
  }
  fillSelectedOriginalItemsList(itemsMap, root, originalItemsList);
  return originalItemsList;
};

const fillSelectedOriginalItemsList = (
  itemsMap: MenuItemV2Map,
  entry: IMenuItemV2Entry,
  originalItemsList: IMenuItemV2[]): void => {
  const originalItem: IMenuItemV2 = { ...entry.originalItem };
  const originalChildren: IMenuItemV2[] = [];
  entry.children.forEach((childId: string) => {
    const child: IMenuItemV2Entry = itemsMap[childId];
    if (child.selected || child.indeterminate) {
      fillSelectedOriginalItemsList(itemsMap, child, originalChildren);
    }
  });
  originalItem.children = originalChildren;
  originalItemsList.push(originalItem);
};

const hasDisabledAndSelectedChildren = (itemsMap: MenuItemV2Map, id: string): IDisabledSelected => {
  let disabled = false;
  let selected = false;
  const entry = itemsMap[id];
  if (entry.children.length === 0) {
    return { disabled, selected };
  }
  entry.children.forEach((childId: string) => {
    const child: IMenuItemV2Entry = itemsMap[childId];
    if (child.disabled) {
      disabled = true;
      if (child.selected) {
        selected = true;
      }
    }
    const disabledAndSelected: IDisabledSelected = hasDisabledAndSelectedChildren(itemsMap, childId);
    disabled = disabled || disabledAndSelected.disabled;
    selected = selected || disabledAndSelected.selected;
  });
  return { disabled, selected };
};

const propagateDisplayChildrenProp = (itemsMap: MenuItemV2Map, parentId: string): void => {
  if (!itemsMap.hasOwnProperty(parentId)) {
    return;
  }
  const childrenIdList: string[] = itemsMap[parentId].children;
  if (childrenIdList.length === 0) {
    return;
  }
  childrenIdList.forEach((childId: string) => {
    const child: IMenuItemV2Entry = itemsMap[childId];
    child.displayChildren = child.storedDisplayChildren;
    propagateDisplayChildrenProp(itemsMap, childId);
  });
};

const propagatePropToChild = <ItemWithProps extends IMenuItemV2Props>(
  propNames: string[],
  parent: ItemWithProps,
  item: ItemWithProps): ItemWithProps => {
  const newItem: ItemWithProps = { ...item };
  propNames.forEach((propName: string) => {
    if (newItem.hasOwnProperty(propName) || !parent.hasOwnProperty(propName)) {
      return;
    }
    newItem[propName] = parent[propName];
  });
  return newItem;
};

const validateAndFixInput = (itemsMap: MenuItemV2Map): MenuItemV2Map => {
  Object.keys(itemsMap).forEach((key: string) => {
    const entry: IMenuItemV2Entry = itemsMap[key];
    const id: string = entry.parentId == null ? 'root' : entry.id;
    if (entry.selected && entry.indeterminate) {
      entry.indeterminate = false;
      itemsMap[id] = entry;
      mxService.logWarning(
        `You cannot set "selected" and "indeterminate" both to true. "indeterminate" will be ignored`,
        entry.originalItem
      );
    }
    if (entry.selected) {
      goDownSelectedIntermediate(id, itemsMap, true, true);
    }
    if (entry.children.length === 0 && entry.indeterminate) {
      entry.indeterminate = false;
      itemsMap[id] = entry;
      mxService.logWarning(`You cannot set "indeterminate" to true for an item without children.
         "indeterminate" will be ignored`, entry.originalItem);
    }
  });

  Object.keys(itemsMap).forEach((key: string) => {
    const entry: IMenuItemV2Entry = itemsMap[key];
    if (entry.children.length === 0) {
      goUpSelectedIndeterminate(entry.parentId, itemsMap);
    }
  });
  return itemsMap;
};

const goDownSelectedIntermediate = (
  id: string,
  itemMap: MenuItemV2Map,
  selected: boolean,
  ignoreDisabled = false): ISelectedIndeterminate => {
  // that's never can happen because this method always takes 'id' from the existing in the map entry
  // but if that is happening that's probably a problem with the data or the component code
  if (!itemMap.hasOwnProperty(id)) {
    mxService.logWarning(`"${id}" was not found in the map.
       That's probably a problem with your data or with the component.
       Please store data you passed into the 'mx-menu-item-v2' and contact developers.`);
    return { selected: false, indeterminate: false };
  }

  const item: IMenuItemV2Entry = itemMap[id];
  let selectedCount = 0;
  let indeterminateCount = 0;
  const considerDisabled: boolean = item.disabled && !ignoreDisabled;
  const childrenLength: number = item.children.length;
  if (childrenLength === 0) {
    return {
      selected: considerDisabled ? item.selected : selected,
      indeterminate: considerDisabled ? item.indeterminate : false
    };
  }

  item.children.forEach((childId: string) => {
    let child: IMenuItemV2Entry = itemMap[childId];
    child = { ...child, ...goDownSelectedIntermediate(childId, itemMap, selected, ignoreDisabled) };
    itemMap[childId] = child;
    if (child.selected) {
      selectedCount++;
    }
    if (child.indeterminate) {
      indeterminateCount++;
    }
  });

  const calcIndeterminate: boolean = indeterminateCount > 0 || (selectedCount > 0 && selectedCount < childrenLength);
  return {
    selected: considerDisabled ? item.selected : selectedCount === childrenLength,
    indeterminate: considerDisabled ? item.indeterminate : calcIndeterminate
  };
};

const goUpSelectedIndeterminate = (parentId: string, itemMap: MenuItemV2Map): void => {
  if (parentId != null && itemMap.hasOwnProperty(parentId)) {
    const parent: IMenuItemV2Entry = itemMap[parentId];
    if (parent.children.length != null) {
      let selectedCount = 0;
      let indeterminateCount = 0;
      parent.children.forEach((childId: string) => {
        const child: IMenuItemV2Entry = itemMap[childId];
        if (child.selected) {
          selectedCount++;
        }
        if (child.indeterminate) {
          indeterminateCount++;
        }
      });
      itemMap[parentId] =  {
        ...parent,
        selected: selectedCount === parent.children.length,
        indeterminate: indeterminateCount > 0 || (selectedCount > 0 && selectedCount < parent.children.length)
      };
      goUpSelectedIndeterminate(parent.parentId, itemMap);
    }
  }
};

const composeItemsStateMap = (items: IMenuItemV2[] | string[], customKeys: CustomKeysV2): MenuItemV2StateMap => {
  if (items == null || items.length === 0) {
    return {};
  }
  const selectedItemsMap = {} as MenuItemV2StateMap;
  items.forEach((selItem: IMenuItemV2 | string) => {
    const setItemValue: string = typeof selItem === 'string' ?
      selItem :
      hasCustomKeys(customKeys) ? selItem[customKeys.value] : (selItem as IMenuItemV2).value;
    selectedItemsMap[setItemValue] = { selected: true, indeterminate: false };
  });
  return selectedItemsMap;
};

const updateSelectedItemInMap = (
  key: string,
  selected: boolean,
  itemMap: MenuItemV2Map): MenuItemV2Map => {
  const item: IMenuItemV2Entry = itemMap[key];
  itemMap[key] = { ...item, ...goDownSelectedIntermediate(key, itemMap, selected) };
  goUpSelectedIndeterminate(item.parentId, itemMap);
  return { ...itemMap };
};

const composeSelectedChildren = (
  items: IMenuItemV2[],
  itemMap: MenuItemV2Map,
  customKeys: CustomKeysV2): IMenuItemV2[] => {
  const selectedItems: IMenuItemV2[] = [];
  if (items == null || items.length === 0) {
    return selectedItems;
  }
  items.forEach((item: IMenuItemV2) => {
    const value: string = hasCustomKeys(customKeys) ? item[customKeys.value] : item.value;
    const itemEntry: IMenuItemV2Entry = itemMap[value];
    if (itemEntry != null && (itemEntry.selected || itemEntry.indeterminate)) {
      selectedItems.push({
        ...item,
        selected: itemEntry.selected,
        indeterminate: itemEntry.indeterminate,
        children: composeSelectedChildren(item.children, itemMap, customKeys) });
    }
  });
  return selectedItems;
};

const getItemsLength = (items: (TreeMenuItem | SelectListItem)[]) => items.reduce((acc, item) => {
  if (item.children) {
    acc += item.children.length + 1;
    return acc;
  }
  acc += 1;
  return acc;
}, 0);

const calculateListHeight = (items: (TreeMenuItem | SelectListItem)[], itemHeight: number): number => {
  const totalItemsHeight: number = getItemsLength(items) * itemHeight;
  return Math.min(totalItemsHeight, minListHeight);
};

export default {
  convertStringToItem,
  convertStringItemsArrayToObjectsArray,
  composeItemMap,
  composeItemMapAccumulated,
  composeItemsStateMap,
  hasCustomKeys,
  composeItemWithCurrentStateFromMap,
  composeSelectedTree,
  hasDisabledAndSelectedChildren,
  propagateDisplayChildrenProp,
  propagatePropToChild,
  validateAndFixInput,
  updateSelectedItemInMap,
  generateItemEntry,
  composeSelectedChildren,
  goUpSelectedIndeterminate,
  getItemsLength,
  calculateListHeight
};
