import packageObject from '../../../package.json';

const MX_WEB_COMPONENTS = 'mx-web-components';

export class MxWebComponentsService {

  libraryId = `[${MX_WEB_COMPONENTS} v${packageObject.version}]`;

  private static _instance: MxWebComponentsService;

  public static get Instance() {
    return this._instance || (this._instance = new MxWebComponentsService());
  }

  public logWarning(message: string, ...args): void {
    console.log(`%c ${this.libraryId}: ${message}`, 'color: #ffac02', ...args);
  }
}
